INSERT INTO `wp_grp_google_review_text` VALUES (1,'531d842f0c6fe5a25d5ca1a176dd059a','fr','Excellente expérience. Ils sont ponctuels et transparents.\nJe recommande!!');
INSERT INTO `wp_grp_google_review_text` VALUES (2,'c69877d3d477123c7621836349f72471','en','I would like to leave an excellent review for the driver assigned to us by the company. From the very beginning, Juan Carlos was extremely professional, punctual, kind, and courteous. He provided outstanding assistance throughout the entire service and was always attentive to every detail with a great attitude.\n\nEverything was very well organized: the transportation, communication, attention, and safety. His service was impeccable, and he made us feel comfortable and confident at all times. I highly recommend him. Thank you very much for providing such high-quality service.');
INSERT INTO `wp_grp_google_review_text` VALUES (3,'86e37a1fd4c33303d680b7cd5b892c5a','en','Great service! Communication was thorough. I knew where to go and found my driver with ease. Best price as well for a private Holbox transfer!');
INSERT INTO `wp_grp_google_review_text` VALUES (4,'6579c64967b717d0f34e562d12a24379','en','Punctual, clean and fast with an excellent safe driver. Our tansfer from Puerto Juarez to Chiquila was made very easy Recommended');
INSERT INTO `wp_grp_google_review_text` VALUES (5,'d6debd5e7657ae623966e6094e425154','en','Timely transfer service pickup. Great communication! Frank was a great driver.');
INSERT INTO `wp_grp_google_review_text` VALUES (6,'08c869205818f2a826d02ec8d1a8b788','en','I transferred from Cancun Airport to Chiquila (to pick up  the Holbox ferry) with Go Holbox transfers, after a late arrival. We were still able to make the second to last ferry to Holbox, thankfully.\n\nThe meeting point and driver were easy to find. The drive was smooth. Keep in mind, there is an option to take a faster toll road (which we did, about USD$10 extra), whose cost is *not* included in the price of the transfer. This is explained in the pre-pick up information sent by the company to the passengers (I didn\'t read it all the way through).\n\nAnyhow, if you fly into Cancun fairly early and are looking for more budget options to get to Holbox, take the ADO Bus. . . otherwise, look no further than Go Holbox!');
INSERT INTO `wp_grp_google_review_text` VALUES (9,'51deaea5009dde45fb576e418a1d2007','en','What a joy to choose Holbox Transfers for our trip from Holbox to Cancun Airport. Their driver Frank waited for us as we were lured to another company wrongly. Got in contact with HT through WhatsApp who helped us out directly. And when our plane was cancelled they drove us to the new hotel we had to stay at to await our new travel time.\n\nOutstanding service, communication and support.');
INSERT INTO `wp_grp_google_review_text` VALUES (15,'e97b52ea27f14fd566c2e39db22250c2','en','We hired Go Holbox Transfers for our airport transfer to Chiquila port on our way to Isla Holbox and we are so happy we did! Booking online was very easy, and the price was very competitive for a group transfer.\n\nUpon landing at Cancun airport, a gentleman was waiting outside with our group name on a sign. He was so friendly and patient while we waited for our whole group to gather. He then escorted us to our van and driver. Our driver, Rene, was fantastic! Friendly, funny, kind, and got us to our destination safely and quickly! We loved him so much that we requested him for our return trip too!\n\nI highly recommend Go Holbox Transfers... if you\'re on the fence or still shopping around, save yourself the time and hassle and book your transfer with Go Holbox!');
/*!40000 ALTER TABLE `wp_grp_google_review_text` ENABLE KEYS */;
UNLOCK TABLES;

