INSERT INTO `wp_options` VALUES (488,'_transient_grw_feed_6.9.8_190_reviews','a:3:{s:10:\"businesses\";a:1:{i:0;O:8:\"stdClass\":8:{s:2:\"id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:4:\"name\";s:19:\"Go holbox transfers\";s:3:\"url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:5:\"photo\";s:91:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ.jpg\";s:7:\"address\";s:75:\"Calle Porfirio Diaz Holbox Island, Quintana Roo, 77310 Holbox, Q.R., Mexico\";s:6:\"rating\";s:3:\"4.8\";s:12:\"review_count\";s:2:\"91\";s:8:\"provider\";s:6:\"google\";}}s:7:\"reviews\";a:7:{i:0;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"2\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:7:\"biz_url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:592:\"I would like to leave an excellent review for the driver assigned to us by the company. From the very beginning, Juan Carlos was extremely professional, punctual, kind, and courteous. He provided outstanding assistance throughout the entire service and was always attentive to every detail with a great attitude.<br />\n<br />\nEverything was very well organized: the transportation, communication, attention, and safety. His service was impeccable, and he made us feel comfortable and confident at all times. I highly recommend him. Thank you very much for providing such high-quality service.\";s:13:\"author_avatar\";s:124:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ_dbcd24b5f2bc98240ea7ffbeb9685400.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/102615392368019959793/reviews\";s:11:\"author_name\";s:16:\"Bernardo Behrens\";s:4:\"time\";s:10:\"1779467812\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:1;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"3\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:7:\"biz_url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:142:\"Great service! Communication was thorough. I knew where to go and found my driver with ease. Best price as well for a private Holbox transfer!\";s:13:\"author_avatar\";s:124:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ_231529daf4848dc8d1c951813605d9e4.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/114465143458895516392/reviews\";s:11:\"author_name\";s:14:\"Marisol Franco\";s:4:\"time\";s:10:\"1777824762\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:2;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"4\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:7:\"biz_url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:129:\"Punctual, clean and fast with an excellent safe driver. Our tansfer from Puerto Juarez to Chiquila was made very easy Recommended\";s:13:\"author_avatar\";s:124:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ_5aad1168573f8c9987fd0973115d71c2.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/115208104302378342201/reviews\";s:11:\"author_name\";s:16:\"Joanna Southgate\";s:4:\"time\";s:10:\"1777657441\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:3;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"5\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:7:\"biz_url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"4\";s:4:\"text\";s:78:\"Timely transfer service pickup. Great communication! Frank was a great driver.\";s:13:\"author_avatar\";s:124:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ_63619f5ba237f5d37e661ec9904d4cbb.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/113092071493388348049/reviews\";s:11:\"author_name\";s:14:\"Lindsay Yodice\";s:4:\"time\";s:10:\"1774213131\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:4;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"6\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:7:\"biz_url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:744:\"I transferred from Cancun Airport to Chiquila (to pick up  the Holbox ferry) with Go Holbox transfers, after a late arrival. We were still able to make the second to last ferry to Holbox, thankfully.<br />\n<br />\nThe meeting point and driver were easy to find. The drive was smooth. Keep in mind, there is an option to take a faster toll road (which we did, about USD$10 extra), whose cost is *not* included in the price of the transfer. This is explained in the pre-pick up information sent by the company to the passengers (I didn\'t read it all the way through).<br />\n<br />\nAnyhow, if you fly into Cancun fairly early and are looking for more budget options to get to Holbox, take the ADO Bus. . . otherwise, look no further than Go Holbox!\";s:13:\"author_avatar\";s:124:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ_1f8645c74698e1badb94cc477d64df1a.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/103550210253961582798/reviews\";s:11:\"author_name\";s:15:\"Amir Abu-Khalil\";s:4:\"time\";s:10:\"1772363152\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:5;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"7\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:7:\"biz_url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:400:\"What a joy to choose Holbox Transfers for our trip from Holbox to Cancun Airport. Their driver Frank waited for us as we were lured to another company wrongly. Got in contact with HT through WhatsApp who helped us out directly. And when our plane was cancelled they drove us to the new hotel we had to stay at to await our new travel time.<br />\n<br />\nOutstanding service, communication and support.\";s:13:\"author_avatar\";s:124:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ_90fc35d9b24fe3023eb3fc923d050ec3.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/103921396471901403233/reviews\";s:11:\"author_name\";s:14:\"Jenny E Kaiser\";s:4:\"time\";s:10:\"1768162280\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}i:6;O:8:\"stdClass\":15:{s:2:\"id\";s:1:\"8\";s:4:\"hide\";s:0:\"\";s:6:\"biz_id\";s:27:\"ChIJFZ_lUJeTTY8Re40wKcMQlcQ\";s:7:\"biz_url\";s:115:\"https://maps.google.com/?cid=14165246633359478139&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA\";s:6:\"rating\";s:1:\"5\";s:4:\"text\";s:791:\"We hired Go Holbox Transfers for our airport transfer to Chiquila port on our way to Isla Holbox and we are so happy we did! Booking online was very easy, and the price was very competitive for a group transfer.<br />\n<br />\nUpon landing at Cancun airport, a gentleman was waiting outside with our group name on a sign. He was so friendly and patient while we waited for our whole group to gather. He then escorted us to our van and driver. Our driver, Rene, was fantastic! Friendly, funny, kind, and got us to our destination safely and quickly! We loved him so much that we requested him for our return trip too!<br />\n<br />\nI highly recommend Go Holbox Transfers... if you\'re on the fence or still shopping around, save yourself the time and hassle and book your transfer with Go Holbox!\";s:13:\"author_avatar\";s:124:\"http://goholboxtransfersv1.local/wp-content/uploads/2026/07/ChIJFZ_lUJeTTY8Re40wKcMQlcQ_7ce69bc39064a7e1e055febe2dec2677.jpg\";s:10:\"author_url\";s:65:\"https://www.google.com/maps/contrib/110369152105575821711/reviews\";s:11:\"author_name\";s:16:\"Charlotte Gulley\";s:4:\"time\";s:10:\"1761539980\";s:6:\"images\";N;s:5:\"reply\";N;s:10:\"reply_time\";N;s:3:\"url\";N;s:8:\"provider\";s:6:\"google\";}}s:7:\"options\";O:8:\"stdClass\":53:{s:9:\"view_mode\";s:6:\"slider\";s:10:\"pagination\";s:0:\"\";s:9:\"text_size\";s:0:\"\";s:13:\"header_center\";b:0;s:17:\"header_hide_photo\";b:0;s:16:\"header_hide_name\";b:0;s:13:\"hide_based_on\";b:0;s:16:\"hide_writereview\";b:0;s:15:\"short_last_name\";b:0;s:10:\"min_letter\";b:0;s:18:\"header_hide_social\";b:0;s:12:\"slider_speed\";s:0:\"\";s:18:\"slider_text_height\";s:0:\"\";s:15:\"slider_autoplay\";b:1;s:16:\"slider_mousestop\";b:1;s:20:\"slider_hide_prevnext\";b:0;s:16:\"slider_hide_dots\";b:0;s:18:\"slider_breakpoints\";s:0:\"\";s:4:\"null\";s:3:\"off\";s:0:\"\";s:1:\"3\";s:12:\"--star-color\";s:7:\"#fb8e28\";s:17:\"--head-name-color\";s:7:\"#333333\";s:18:\"--head-based-color\";s:7:\"#555555\";s:15:\"--powered-color\";s:7:\"#777777\";s:11:\"--btn-color\";s:7:\"#1f67e7\";s:11:\"--rev-color\";b:0;s:12:\"--name-color\";s:7:\"#154fc1\";s:12:\"--text-color\";s:7:\"#222222\";s:10:\"dark_theme\";b:0;s:10:\"show_round\";b:1;s:11:\"show_shadow\";b:0;s:10:\"style_vars\";s:0:\"\";s:13:\"lazy_load_img\";b:1;s:13:\"nofollow_link\";b:1;s:9:\"open_link\";b:1;s:10:\"aria_label\";b:0;s:5:\"media\";b:1;s:5:\"reply\";b:1;s:19:\"google_def_rev_link\";b:0;s:20:\"reviewer_avatar_size\";s:2:\"56\";s:5:\"cache\";s:2:\"12\";s:13:\"reviews_limit\";s:0:\"\";s:6:\"hidden\";s:0:\"\";s:17:\"disable_user_link\";b:0;s:12:\"hide_reviews\";b:0;s:11:\"hide_avatar\";b:0;s:12:\"hide_backgnd\";b:0;s:18:\"slider_hide_border\";b:0;s:19:\"header_merge_social\";b:0;s:8:\"centered\";b:0;s:9:\"max_width\";s:0:\"\";s:10:\"max_height\";s:0:\"\";s:10:\"star_style\";s:0:\"\";}}','off');
